INSERT INTO books (id, title, author, description, isbn, published_year, created_by, created_at, updated_at) VALUES
('f5eebc99-9c0b-4ef8-bb6d-6bb9bd380b01', 'Чистая архитектура', 'Роберт Мартин', 'Практическое руководство по программной архитектуре от легендарного Дядюшки Боба. Книга охватывает принципы SOLID, компонентную архитектуру и границы системы.', '978-5-4461-0772-8', 2018, 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11', '2024-01-15 10:00:00+00', '2024-01-15 10:00:00+00'),
('f6eebc99-9c0b-4ef8-bb6d-6bb9bd380b02', 'Чистый код', 'Роберт Мартин', 'Справочник для создания читаемого, поддерживаемого и эффективного кода. Множество примеров на Java с универсальными принципами.', '978-5-4461-0960-9', 2008, 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11', '2024-01-16 11:30:00+00', '2024-01-16 11:30:00+00'),
('f7eebc99-9c0b-4ef8-bb6d-6bb9bd380b03', 'Паттерны проектирования', 'Банда четырёх', 'Классическая книга о паттернах объектно-ориентированного проектирования. 23 паттерна, которые должен знать каждый разработчик.', '978-5-496-00389-0', 1994, 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', '2024-01-20 09:00:00+00', '2024-01-20 09:00:00+00'),
('f8eebc99-9c0b-4ef8-bb6d-6bb9bd380b04', 'Программист-прагматик', 'Дэвид Томас, Эндрю Хант', 'От подмастерья к мастеру. Книга о профессиональном развитии программиста, инструментах и практиках.', '978-5-6041394-5-4', 2019, 'c2eebc99-9c0b-4ef8-bb6d-6bb9bd380a13', '2024-01-25 14:20:00+00', '2024-01-25 14:20:00+00'),
('f9eebc99-9c0b-4ef8-bb6d-6bb9bd380b05', 'Рефакторинг', 'Мартин Фаулер', 'Улучшение существующего кода. Каталог рефакторингов с примерами и мотивацией для каждого преобразования.', '978-5-6041394-6-1', 2018, 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11', '2024-02-01 10:00:00+00', '2024-02-01 10:00:00+00'),
('fa0ebc99-9c0b-4ef8-bb6d-6bb9bd380b06', 'Domain-Driven Design', 'Эрик Эванс', 'Предметно-ориентированное проектирование. Структурирование сложных программных систем.', '978-5-9775-0445-1', 2003, 'd3eebc99-9c0b-4ef8-bb6d-6bb9bd380a14', '2024-02-05 16:00:00+00', '2024-02-05 16:00:00+00'),
('fa1ebc99-9c0b-4ef8-bb6d-6bb9bd380b07', 'Микросервисы. Паттерны разработки', 'Крис Ричардсон', 'Практическое руководство по проектированию микросервисной архитектуры с примерами на Java.', '978-5-4461-1150-3', 2019, 'e4eebc99-9c0b-4ef8-bb6d-6bb9bd380a15', '2024-02-10 12:00:00+00', '2024-02-10 12:00:00+00'),
('fa2ebc99-9c0b-4ef8-bb6d-6bb9bd380b08', 'Высоконагруженные приложения', 'Мартин Клеппман', 'Designing Data-Intensive Applications. Принципы проектирования надёжных, масштабируемых систем.', '978-5-4461-0512-0', 2017, 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11', '2024-02-15 09:30:00+00', '2024-02-15 09:30:00+00'),
('fa3ebc99-9c0b-4ef8-bb6d-6bb9bd380b09', 'Язык программирования Go', 'Алан Донован, Брайан Керниган', 'Официальное руководство по языку Go от создателей. Охватывает все аспекты языка с примерами.', '978-5-8459-2051-5', 2015, 'c2eebc99-9c0b-4ef8-bb6d-6bb9bd380a13', '2024-02-20 11:00:00+00', '2024-02-20 11:00:00+00'),
('fa4ebc99-9c0b-4ef8-bb6d-6bb9bd380b10', 'Concurrency in Go', 'Кэтрин Кокс-Будай', 'Инструменты и техники для разработки конкурентных программ на Go. Горутины, каналы, паттерны.', '978-1-491-94119-5', 2017, 'd3eebc99-9c0b-4ef8-bb6d-6bb9bd380a14', '2024-02-25 14:00:00+00', '2024-02-25 14:00:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('11111111-1111-1111-1111-111111111111', 'f5eebc99-9c0b-4ef8-bb6d-6bb9bd380b01', 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', 5, 'Фундаментальная книга', 'Обязательна к прочтению для любого разработчика. Принципы SOLID и архитектурные границы объяснены превосходно.', '2024-02-01 14:30:00+00', '2024-02-01 14:30:00+00'),
('11111111-1111-1111-1111-111111111112', 'f5eebc99-9c0b-4ef8-bb6d-6bb9bd380b01', 'c2eebc99-9c0b-4ef8-bb6d-6bb9bd380a13', 4, 'Хорошо, но много повторений', 'Отличные идеи, но некоторые концепции повторяются в разных главах. В целом очень полезно.', '2024-02-05 10:15:00+00', '2024-02-05 10:15:00+00'),
('11111111-1111-1111-1111-111111111113', 'f5eebc99-9c0b-4ef8-bb6d-6bb9bd380b01', 'd3eebc99-9c0b-4ef8-bb6d-6bb9bd380a14', 5, 'Изменила мой подход к коду', 'После прочтения полностью пересмотрел структуру своих проектов. Особенно полезна глава о границах.', '2024-02-10 16:00:00+00', '2024-02-10 16:00:00+00'),
('11111111-1111-1111-1111-111111111114', 'f5eebc99-9c0b-4ef8-bb6d-6bb9bd380b01', 'e4eebc99-9c0b-4ef8-bb6d-6bb9bd380a15', 4, 'Классика архитектуры', 'Хорошая книга, хотя примеры немного устарели. Принципы остаются актуальными.', '2024-02-15 11:30:00+00', '2024-02-15 11:30:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('22222222-2222-2222-2222-222222222221', 'f6eebc99-9c0b-4ef8-bb6d-6bb9bd380b02', 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', 5, 'Библия программиста', 'Каждый разработчик должен прочитать эту книгу хотя бы раз. Примеры на Java, но принципы универсальны.', '2024-02-01 10:00:00+00', '2024-02-01 10:00:00+00'),
('22222222-2222-2222-2222-222222222222', 'f6eebc99-9c0b-4ef8-bb6d-6bb9bd380b02', 'c2eebc99-9c0b-4ef8-bb6d-6bb9bd380a13', 5, 'Практические советы', 'Много конкретных примеров и рефакторингов. Особенно понравилась глава о юнит-тестах.', '2024-02-08 14:20:00+00', '2024-02-08 14:20:00+00'),
('22222222-2222-2222-2222-222222222223', 'f6eebc99-9c0b-4ef8-bb6d-6bb9bd380b02', 'd3eebc99-9c0b-4ef8-bb6d-6bb9bd380a14', 4, 'Хорошо, но спорно', 'Некоторые рекомендации слишком категоричны. Но в целом книга формирует правильное мышление.', '2024-02-12 11:00:00+00', '2024-02-12 11:00:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('33333333-3333-3333-3333-333333333331', 'fa2ebc99-9c0b-4ef8-bb6d-6bb9bd380b08', 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', 5, 'Шедевр!', 'Лучшая книга по распределённым системам. Глубокое погружение в репликацию, партиционирование, консенсус.', '2024-03-01 10:00:00+00', '2024-03-01 10:00:00+00'),
('33333333-3333-3333-3333-333333333332', 'fa2ebc99-9c0b-4ef8-bb6d-6bb9bd380b08', 'c2eebc99-9c0b-4ef8-bb6d-6bb9bd380a13', 5, 'Обязательна для backend разработчиков', 'Невероятно глубокая и при этом понятная. Каждую главу хочется перечитывать.', '2024-03-05 15:30:00+00', '2024-03-05 15:30:00+00'),
('33333333-3333-3333-3333-333333333333', 'fa2ebc99-9c0b-4ef8-bb6d-6bb9bd380b08', 'e4eebc99-9c0b-4ef8-bb6d-6bb9bd380a15', 5, NULL, 'DDIA — это база. После неё начинаешь понимать, как работают real-world системы.', '2024-03-10 09:15:00+00', '2024-03-10 09:15:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('44444444-4444-4444-4444-444444444441', 'fa1ebc99-9c0b-4ef8-bb6d-6bb9bd380b07', 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', 4, 'Хороший обзор паттернов', 'Систематизирует знания о микросервисах. Saga, CQRS, Event Sourcing — всё на месте.', '2024-03-01 11:00:00+00', '2024-03-01 11:00:00+00'),
('44444444-4444-4444-4444-444444444442', 'fa1ebc99-9c0b-4ef8-bb6d-6bb9bd380b07', 'd3eebc99-9c0b-4ef8-bb6d-6bb9bd380a14', 5, 'Практично и современно', 'Отличная книга для тех, кто переходит с монолита на микросервисы. Много примеров.', '2024-03-08 14:00:00+00', '2024-03-08 14:00:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('55555555-5555-5555-5555-555555555551', 'fa3ebc99-9c0b-4ef8-bb6d-6bb9bd380b09', 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11', 5, 'Лучшая книга по Go', 'Написана создателями языка. Примеры идиоматичны, объяснения понятны. Must read для гоферов.', '2024-03-15 10:30:00+00', '2024-03-15 10:30:00+00'),
('55555555-5555-5555-5555-555555555552', 'fa3ebc99-9c0b-4ef8-bb6d-6bb9bd380b09', 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', 4, 'Отличный справочник', 'Глубокое погружение в язык. Подходит как для новичков, так и для опытных разработчиков.', '2024-03-18 12:00:00+00', '2024-03-18 12:00:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('66666666-6666-6666-6666-666666666661', 'f7eebc99-9c0b-4ef8-bb6d-6bb9bd380b03', 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11', 4, 'Классика, но сложно', 'Книга сложная для новичков, но паттерны описаны исчерпывающе. Лучше читать с опытом.', '2024-02-25 10:00:00+00', '2024-02-25 10:00:00+00');
INSERT INTO reviews (id, book_id, user_id, rating, title, content, created_at, updated_at) VALUES
('77777777-7777-7777-7777-777777777771', 'f8eebc99-9c0b-4ef8-bb6d-6bb9bd380b04', 'b1eebc99-9c0b-4ef8-bb6d-6bb9bd380a12', 5, 'Меняет мышление', 'Книга не о коде, а о профессии. DRY, YAGNI, tracer bullets — концепции на всю карьеру.', '2024-03-01 16:00:00+00', '2024-03-01 16:00:00+00');
